1	export const runScenario = (_scenario: unknown): { results: unknown[] } => {
2	  return { results: [{ premium: 5 }] };
3	};
4

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Quote: simplest cases (edge cases) ---
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // --- Quote: base premiums for main items ---
15	  it.todo("single sword (steel, ench 0, not cursed), new customer's first contract → 100 base + 10 first-insurance + 5 fee = 115 G");
16	  it.todo("single amulet → 60 base + 6 first-insurance + 5 fee = 71 G");
17	  it.todo("single staff → 80 base + 8 first-insurance + 5 fee = 93 G");
18	  it.todo("single potion → 40 base + 4 first-insurance + 5 fee = 49 G");
19	
20	  // --- Quote: components and blocks ---
21	  it.todo("2 runes → 50 G base + 5 first-insurance + 5 fee = 60 G");
22	  it.todo("3 runes → 60 G base (block applies) + 6 first-insurance + 5 fee = 71 G");
23	  it.todo("4 runes → 100 G base (no block — block requires exactly 3) + 10 first-insurance + 5 fee = 115 G");
24	  it.todo("7 runes → 175 G base + 18 first-insurance (rounded up) + 5 fee = 198 G");
25	  it.todo("2 runes + 1 moonstone → 75 G base (no block: different types)");
26	  it.todo("3 runes + 3 moonstones → 120 G base (two separate blocks)");
27	
28	  // --- Quote: item-specific modifiers ---
29	  it.todo("cursed sword adds 50% risk surcharge to the cursed item only");
30	  it.todo("highly enchanted item (ench ≥ 5) adds 30% risk surcharge");
31	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
32	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
33	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
34	
35	  // --- Quote: policy-wide modifiers ---
36	  it.todo("long-standing customer (≥ 2 years) receives 20% loyalty discount on policy base");
37	  it.todo("customer with exactly 2 years → loyalty discount applies");
38	  it.todo("first insurance carries 10% initial assessment surcharge per item");
39	  it.todo("follow-up contract (each contract after the first) gets 15% discount");
40	  it.todo("5 G processing fee added to every premium");
41	
42	  // --- Quote: scope clarifications (❓) ---
43	  it.todo("cursed sword + plain amulet → 100+60=160 base, +50 curse on sword, +21 first-insurance, -15 follow-up doesn't apply (first contract) → 210 G before fee ; example: cursed sword (100) + plain amulet (60) → 210 G before further modifiers and fee");
44	  it.todo("first-insurance surcharge applies per item even for follow-up contracts");
45	
46	  // --- Quote: rounding (in MHPCO's favor = round premium up) ---
47	  it.todo("premium calculation 197.5 G → 198 G (rounded up)");
48	  it.todo("intermediate amounts kept as fractions; only final premium rounded");
49	
50	  // --- Quote: error cases ---
51	  it.todo("quote includes item with unknown type → CLI exits non-zero, error to stderr, no results to stdout");
52	
53	  // --- Quote: integration examples ---
54	  it.todo("newcomer (0 years, no prev contract) with cursed sword (steel, ench 3) → 165 G");
55	  it.todo("long-standing customer (3 years), 2nd quote, cursed sword (steel, ench 7) → 160 G");
56	
57	  // --- Claim: standard reimbursement ---
58	  it.todo("regular sword (steel, ench 3) damaged 500 G → payout 400 G (500 - 100 deductible)");
59	  it.todo("rune (insurance value 250 G) damaged 200 G → payout 100 G");
60	
61	  // --- Claim: enchantment threshold ---
62	  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (50% then deductible)");
63	  it.todo("dragon-material sword ench 8, damage 1000 G → payout 400 G (ench rule wins, then deductible)");
64	
65	  // --- Claim: dragon material ---
66	  it.todo("dragon-material sword ench 5, damage 800 G → payout 700 G (full reimbursement, then deductible)");
67	
68	  // --- Claim: both clauses ---
69	  it.todo("dragon-material sword ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
70	
71	  // --- Claim: deductible per damage event ---
72	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");
73	
74	  // --- Claim: multiple items of same type ---
75	  it.todo("two-sword policy → insurance sum 2000 G, cap 4000 G");
76	  it.todo("two sword damages on two-sword policy → each treated as separate damage with own deductible");
77	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero, claim rejected");
78	
79	  // --- Claim: cap based on insurance values ---
80	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
81	  it.todo("cursed sword (premium 165 G with modifiers) → cap 2000 G (based on unmodified insurance value)");
82	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount doesn't affect insurance sum)");
83	
84	  // --- Claim: cap exhaustion across successive claims ---
85	  it.todo("sword cap 2000 G, first claim 1500 G damage → payout 1400 G, cap remaining 600 G");
86	  it.todo("sword cap 2000 G, second claim 1500 G after first exhausted to 600 → payout 600 G, cap remaining 0");
87	
88	  // --- Claim: rounding (in MHPCO's favor = round payout down) ---
89	  it.todo("payout calculation 350.5 G → 350 G (rounded down)");
90	
91	  // --- Claim: error cases ---
92	  it.todo("claim references damage entry whose item is not part of policy → CLI exits non-zero, error to stderr");
93	  it.todo("claim references item with unknown type → CLI exits non-zero, error to stderr");
94	  it.todo("claim contains damage entry with amount: -200 → CLI exits non-zero, error to stderr");
95	
96	  // --- CLI / scenario level ---
97	  it.todo("scenario with single quote step produces results array with one premium");
98	  it.todo("scenario with quote then claim returns premium then payout + remainingCap");
99	  it.todo("CLI reads JSON from stdin and writes JSON to stdout");
100	});
